                              className="bp-suggest-chip"
                              onClick={() => openBookingOrPrompt(s.serviceId)}
                            >
                              <span className="bp-suggest-chip-name">
                                {s.serviceName}
                              </span>
                              <span className="bp-suggest-chip-count" aria-hidden>
                                ×{s.bookCount}
                              </span>
                            </button>
                          ))}
