                                <path
                                  d="M7 4V7L9 8.5"
                                  stroke="currentColor"
                                  strokeWidth="1.2"
                                  strokeLinecap="round"
                                />
                              </svg>
                              {service.duration} min
                            </span>
                          </div>
                          <div className="bp-service-right">
                            <div className="bp-service-price-stack">
                              {pv ? (
                                <>
                                  <span className="bp-service-price-old">
                                    {formatMoneyCompact(
                                      pv.basePrice,
                                      business.currency,
                                    )}
                                  </span>
                                  <span className="bp-service-price">
                                    {formatMoneyCompact(
                                      pv.salePrice,
                                      business.currency,
                                    )}
                                  </span>
                                </>
                              ) : (
                                <span className="bp-service-price">
                                  {formatMoneyCompact(
                                    service.price,
                                    business.currency,
                                  )}
                                </span>
                              )}
                            </div>
                            <button
                              type="button"
                              className="bp-service-book-btn"
                              onClick={() => openBookingOrPrompt(service.id)}
                            >
                              Book
                            </button>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
                </>
              )}

              {activeTab === "reviews" && (
                <div className="bp-reviews-section">
                  <div className="bp-reviews-summary">
                    <div>
                      <span className="bp-big-number">{business.rating}</span>
                      <StarRating rating={business.rating} size={18} />
                      <span className="bp-review-total">
                        {business.reviewCount} reviews
                      </span>
                    </div>
                    <button
                      type="button"
                      className="bp-write-review-btn"
                      onClick={openReviewOrPrompt}
                    >
                      Write a Review
                    </button>
                  </div>
                  {business.reviews.length === 0 ? (
                    <p className="bp-empty-hint">No reviews yet.</p>
                  ) : (
                    <div className="bp-reviews-list">
                      {business.reviews.map((review, i) => (
                        <div
                          key={review.id ?? i}
                          className="bp-review-card"
                          style={{ animationDelay: `${i * 80}ms` }}
                        >
                          <div className="bp-review-header">
                            <img
                              src={review.avatar}
                              alt={review.name}
                              className="bp-review-avatar"
                            />
                            <div>
                              <span className="bp-review-name">
                                {review.name}
                              </span>
                              <span className="bp-review-date">
                                {review.date}
                              </span>
                            </div>
                            <div className="bp-review-rating">
                              <StarRating rating={review.rating} size={12} />
                            </div>
                          </div>
                          <p className="bp-review-text">{review.text}</p>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {activeTab === "gallery" && (
                <div className="bp-gallery-section">
                  {business.gallery.length === 0 ? (
                    <p className="bp-empty-hint">
                      No photos have been added yet.
                    </p>
                  ) : (
                    <ul
                      className="bp-gallery-grid"
                      aria-label={`${business.name} gallery`}
                    >
                      {business.gallery.map((g, i) => (
                        <li
                          key={`${g.url}-${i}`}
                          className="bp-gallery-cell"
                          style={{ animationDelay: `${Math.min(i, 12) * 40}ms` }}
                        >
                          <button
                            type="button"
                            className="bp-gallery-thumb"
                            style={{ backgroundImage: `url(${g.url})` }}
                            onClick={() => {
                              setLightboxIndex(i);
                              setLightboxOpen(true);
                            }}
                            aria-label={
                              g.caption || `Open image ${i + 1} of ${business.gallery.length}`
                            }
                          >
                            <span className="bp-gallery-zoom" aria-hidden>
                              <svg
                                width="20"
                                height="20"
                                viewBox="0 0 20 20"
                                fill="none"
                              >
                                <circle
                                  cx="9"
                                  cy="9"
                                  r="6"
                                  stroke="currentColor"
                                  strokeWidth="1.8"
                                />
                                <path
                                  d="M13.5 13.5L17 17"
                                  stroke="currentColor"
                                  strokeWidth="1.8"
                                  strokeLinecap="round"
                                />
                                <path
                                  d="M6 9H12M9 6V12"
                                  stroke="currentColor"
                                  strokeWidth="1.6"
                                  strokeLinecap="round"
                                />
                              </svg>
                            </span>
                            {g.caption ? (
                              <span className="bp-gallery-caption-overlay">
                                {g.caption}
                              </span>
                            ) : null}
                          </button>
                        </li>
                      ))}
                    </ul>
                  )}
                </div>
              )}

              {activeTab === "about" && (
                <div className="bp-about-section">
                  <div className="bp-about-block">
                    <h3>About Us</h3>
                    <p>
                      {business.description ||
                        "No description has been added yet."}
                    </p>
                  </div>
                  <div className="bp-about-block">
                    <h3>Our Team</h3>
                    {business.staff.length === 0 ? (
                      <p className="bp-empty-hint">No team members listed.</p>
                    ) : (
                      <>
                        <p className="bp-team-hint bp-team-hint--about">
                          You can rate a team member from here or from the
                          sidebar on the right (after you sign in and have a
                          finished visit with them).
                        </p>
                        <div className="bp-staff-grid">
                          {business.staff.map((member, i) => {
                            const canRateStaff = eligibleStaffReviews.some(
                              (e) => e.staffId === member.id,
                            );
                            return (
                              <div
                                key={member.id}
                                className="bp-staff-card"
                                style={{ animationDelay: `${i * 100}ms` }}
                              >
                                <img
                                  src={member.avatar}
                                  alt={member.name}
                                  className="bp-staff-avatar"
                                />
                                <span className="bp-staff-name">
                                  {member.name}
                                </span>
                                <span className="bp-staff-role">
                                  {member.role}
                                </span>
                                {canRateStaff ? (
                                  <button
                                    type="button"
                                    className="bp-member-rate-btn bp-member-rate-btn--card"
                                    onClick={() =>
                                      openStaffReviewForMember(member)
                                    }
                                  >
                                    Rate
                                  </button>
                                ) : null}
                              </div>
                            );
                          })}
                        </div>
                      </>
                    )}
                  </div>
                  <div className="bp-about-block">
                    <h3>Working Hours</h3>
                    {business.workingHours.length === 0 ? (
                      <p className="bp-empty-hint">No hours listed.</p>
                    ) : (
                      <div className="bp-hours-list">
                        {business.workingHours.map((item, i) => (
                          <div
                            key={i}
                            className={`bp-hours-row ${item.day === todayName ? "today" : ""}`}
                          >
                            <span className="bp-hours-day">{item.day}</span>
                            <span
                              className={`bp-hours-time ${item.hours === "Closed" ? "closed" : ""}`}
                            >
                              {item.hours}
                            </span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                  <div className="bp-about-block">
                    <h3>Contact</h3>
                    <div className="bp-contact-list">
                      <a
                        href={`tel:${business.phone}`}
                        className="bp-contact-item"
                      >
                        <svg
                          width="16"
                          height="16"
                          viewBox="0 0 16 16"
                          fill="none"
                        >
                          <path
                            d="M14 11.3V13.3C14 13.7 13.7 14 13.3 14C6.6 14 1 8.4 1 1.7C1 1.3 1.3 1 1.7 1H3.7C4.1 1 4.4 1.3 4.4 1.7C4.4 2.8 4.6 3.8 5 4.7L3.6 6.1C4.7 8.3 6.7 10.3 8.9 11.4L10.3 10C11.2 10.4 12.2 10.6 13.3 10.6C13.7 10.6 14 10.9 14 11.3Z"
                            stroke="currentColor"
                            strokeWidth="1.2"
                          />
                        </svg>
                        <span>{business.phone || "—"}</span>
                      </a>
                      {business.email ? (
                        <a
                          href={`mailto:${business.email}`}
                          className="bp-contact-item"
                        >
                          <svg
                            width="16"
                            height="16"
                            viewBox="0 0 16 16"
                            fill="none"
                          >
                            <rect
                              x="1"
                              y="3"
                              width="14"
                              height="10"
                              rx="1.5"
                              stroke="currentColor"
                              strokeWidth="1.2"
                            />
                            <path
                              d="M1 4.5L8 9L15 4.5"
                              stroke="currentColor"
                              strokeWidth="1.2"
                            />
                          </svg>
                          <span>{business.email}</span>
                        </a>
                      ) : null}
                      <div className="bp-contact-item">
                        <svg
                          width="16"
                          height="16"
                          viewBox="0 0 16 16"
                          fill="none"
                        >
                          <path
                            d="M14 7C14 11 8 15 8 15C8 15 2 11 2 7C2 3.69 4.69 1 8 1C11.31 1 14 3.69 14 7Z"
                            stroke="currentColor"
                            strokeWidth="1.2"
                          />
                          <circle
                            cx="8"
                            cy="7"
                            r="2"
                            stroke="currentColor"
                            strokeWidth="1.2"
                          />
                        </svg>
                        <span>{business.address || "—"}</span>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <aside className="bp-sidebar">
              <div className="bp-booking-card">
                <h3>Book an Appointment</h3>
                <p>Choose a service and pick a time that works for you</p>
                {business.closingPeriods?.length > 0 ? (
                  <div className="bp-closing-notice" role="status">
                    <div className="bp-closing-notice-title">
                      Not accepting new bookings during:
                    </div>
                    <ul className="bp-closing-notice-list">
                      {business.closingPeriods.map((p) => (
                        <li key={p.id}>
                          <span className="bp-closing-notice-range">
                            {formatClosingPeriodRange(p)}
                          </span>
                          {p.reason ? (
                            <span className="bp-closing-notice-reason">
                              {" "}
                              ({p.reason})
                            </span>
                          ) : null}
                        </li>
                      ))}
                    </ul>
                  </div>
                ) : null}
                <div className="bp-booking-preview">
                  <div className="bp-booking-row">
                    <span>Services available</span>
                    <span className="bp-booking-val">
                      {business.services.length}
                    </span>
                  </div>
                  <div className="bp-booking-row">
                    <span>Starting from</span>
                    <span className="bp-booking-val">
                      {minPrice != null
                        ? formatMoneyCompact(minPrice, business.currency)
                        : "—"}
                    </span>
                  </div>
                  <div className="bp-booking-row">
                    <span>Team members</span>
                    <span className="bp-booking-val">
                      {business.staff.length}
                    </span>
                  </div>
                </div>
                <button
                  type="button"
                  className="bp-booking-cta"
                  onClick={() => openBookingOrPrompt(null)}
                >
                  View Services & Book
                  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                    <path
                      d="M3 8H13M13 8L9 4M13 8L9 12"
                      stroke="currentColor"
                      strokeWidth="1.5"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                    />
                  </svg>
                </button>

                <button
                  type="button"
                  className="bp-review-sidebar-btn"
                  onClick={openReviewOrPrompt}
                >
                  <HiOutlineStar size={18} aria-hidden className="bp-review-sidebar-btn-icon" />
                  Leave a Review
                </button>
              </div>
              <div className="bp-sidebar-card">
                <h4>Our Team</h4>
                {business.staff.length > 0 ? (
                  <p className="bp-team-hint">
                    {!isAuthenticated
                      ? "Sign in to rate a provider after your visit — a Rate button appears next to their name when you’re eligible."
                      : eligibleStaffReviews.length > 0
                        ? "Tap Rate next to someone you’ve already visited. Only the business sees this (not on the public Reviews tab)."
                        : "Rate shows up here after a past appointment has ended with that person (your booking must be confirmed or completed)."}
                  </p>
                ) : null}
                <div className="bp-sidebar-staff">
                  {business.staff.length === 0 ? (
                    <p className="bp-empty-hint bp-empty-hint--compact">
                      No team listed yet.
                    </p>
                  ) : (
                    business.staff.map((member) => {
                      const canRateStaff = eligibleStaffReviews.some(
                        (e) => e.staffId === member.id,
                      );
                      return (
                        <div key={member.id} className="bp-sidebar-member">
                          <img src={member.avatar} alt={member.name} />
                          <div className="bp-sidebar-member-text">
                            <span className="bp-member-name">{member.name}</span>
                            <span className="bp-member-role">{member.role}</span>
                          </div>
                          {canRateStaff ? (
                            <button
                              type="button"
                              className="bp-member-rate-btn"
                              onClick={() => openStaffReviewForMember(member)}
                            >
                              Rate
                            </button>
                          ) : null}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>
            </aside>
          </div>
        </div>
      </section>
      <ReviewModal
        isOpen={reviewModalOpen}
        onClose={() => {
          setReviewModalOpen(false);
          setStaffReviewModalContext(null);
        }}
        businessName={business.name}
        businessId={business.businessId}
        onSuccess={async () => {
          await refetchBusiness();
          try {
            const { data } = await getStaffReviewEligible({
              businessId: business.businessId,
            });
            setEligibleStaffReviews(
              Array.isArray(data?.eligible) ? data.eligible : [],
            );
          } catch {
            setEligibleStaffReviews([]);
          }
        }}
        staffReviewContext={staffReviewModalContext}
      />
      <AuthPromptModal
        isOpen={authPromptOpen}
        onClose={() => setAuthPromptOpen(false)}
        returnTo={returnTo}
      />
      <BookingModal
        isOpen={bookingOpen}
        onClose={() => {
          setBookingOpen(false);
          setBookingInitialServiceId(null);
        }}
        businessName={business.name}
        businessId={business.businessId}
        services={business.services}
        staff={business.staff}
        initialServiceId={bookingInitialServiceId}
        closingPeriods={business.closingPeriods}
        maxAdvanceDays={business.maxAdvanceDays}
        currencyCode={business.currency}
        initialWaitlistToken={waitlistToken || undefined}
        onWaitlistPrefillConsumed={consumeWaitlistUrl}
      />
      <ImageLightbox
        open={lightboxOpen}
        onClose={() => setLightboxOpen(false)}
        images={business.gallery}
        index={lightboxIndex}
        onIndexChange={setLightboxIndex}
        alt={`${business.name} gallery`}
      />
    </main>
  );
};

export default BusinessProfile;

import { useEffect, useMemo, useRef, useState } from "react";
import { Navigate, useOutletContext } from "react-router-dom";
import {
  HiOutlineSearch,
  HiOutlineTrash,
  HiOutlineUserAdd,
  HiOutlineUserGroup,
  HiOutlineX,
} from "react-icons/hi";
import {
  createAdminUser,
  listManagedUsers,
  deleteManagedUser,
  updateManagedUserRole,
} from "../../api/users";
import {
  getApiErrorMessage,
  verifyEmail as verifyEmailRequest,
  resendVerification as resendVerificationRequest,
} from "../../api/auth";
import { isAdminRole } from "../../utils/roles";
import { useToast } from "../../components/ToastContext";
import VerifyEmailModal from "../Auth/VerifyEmailModal";
import CustomSelect from "../../utils/CustomSelect";
import "./dashboard-pages.css";

export default function AdminManageAdmins() {
  const { user } = useOutletContext();
  const { showToast } = useToast();
  const [submitting, setSubmitting] = useState(false);
  const [verifyModalOpen, setVerifyModalOpen] = useState(false);
  const [pendingEmail, setPendingEmail] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [searchQuery, setSearchQuery] = useState("");
  const [accounts, setAccounts] = useState([]);
  const [loadingList, setLoadingList] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const [updatingRoleId, setUpdatingRoleId] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [undoDelete, setUndoDelete] = useState(null);
  const [undoCountdown, setUndoCountdown] = useState(0);
  const undoTimerRef = useRef(null);
  const undoIntervalRef = useRef(null);
  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    role: "admin",
  });

  if (!isAdminRole(user?.role)) {
    return <Navigate to="/dashboard" replace />;
  }

  const canSubmit =
    form.name.trim().length > 0 &&
    form.email.trim().length > 0 &&
    form.password.length >= 6 &&
    !submitting;

  const roleOptions = useMemo(
    () => [
      { value: "admin", label: "Admin" },
      { value: "tenant", label: "Tenant" },
      { value: "customer", label: "Customer" },
    ],
    [],
  );

  const filterOptions = useMemo(
    () => [{ value: "all", label: "All roles" }, ...roleOptions],
    [roleOptions],
  );

  const roleBadgeLabel = (role) => (role === "customer" ? "user" : role);
  const normalizedSearch = searchQuery.trim().toLowerCase();

  const visibleAccounts = useMemo(() => {
    if (!normalizedSearch) return accounts;
    return accounts.filter((account) => {
      const name = String(account?.name || "").toLowerCase();
      const email = String(account?.email || "").toLowerCase();
      return name.includes(normalizedSearch) || email.includes(normalizedSearch);
    });
  }, [accounts, normalizedSearch]);

  const loadAccounts = async () => {
    setLoadingList(true);
    try {
      const params = roleFilter === "all" ? {} : { role: roleFilter };
      const { data } = await listManagedUsers(params);
      setAccounts(Array.isArray(data?.accounts) ? data.accounts : []);
    } catch (err) {
      showToast(getApiErrorMessage(err), "error");
      setAccounts([]);
    } finally {
      setLoadingList(false);
    }
  };

  useEffect(() => {
    loadAccounts();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [roleFilter]);

  useEffect(() => {
    return () => {
      if (undoTimerRef.current) {
        window.clearTimeout(undoTimerRef.current);
      }
      if (undoIntervalRef.current) {
        window.clearInterval(undoIntervalRef.current);
      }
    };
  }, []);

  const onSubmit = async (e) => {
    e.preventDefault();
    if (!canSubmit) return;
    setSubmitting(true);
    try {
      const { data } = await createAdminUser({
        name: form.name.trim(),
        email: form.email.trim().toLowerCase(),
        password: form.password,
        role: form.role,
      });
      const e = String(data?.email || form.email || "")
        .trim()
        .toLowerCase();
      setPendingEmail(e);
      setVerifyModalOpen(true);
      showToast("Verification code sent to the new admin email.", "success");
      setForm({ name: "", email: "", password: "", role: "admin" });
      await loadAccounts();
    } catch (err) {
      showToast(getApiErrorMessage(err), "error");
    } finally {
      setSubmitting(false);
    }
  };

  const confirmRemoveAccount = (account) => {
    if (!account?.id) return;
    setDeleteConfirm(account);
  };

  const closeDeleteModal = () => {
    if (deletingId) return;
    setDeleteConfirm(null);
  };

  const performDeleteWithUndo = async () => {
    const account = deleteConfirm;
    if (!account?.id) return;
    setDeleteConfirm(null);
    setDeletingId(account.id);

    if (undoTimerRef.current) {
      window.clearTimeout(undoTimerRef.current);
    }
    if (undoIntervalRef.current) {
      window.clearInterval(undoIntervalRef.current);
    }

    const expiresAt = Date.now() + 10000;
    setUndoDelete({ account, expiresAt });
    setUndoCountdown(10);
    undoIntervalRef.current = window.setInterval(() => {
      setUndoCountdown((prev) => (prev <= 1 ? 0 : prev - 1));
    }, 1000);
    showToast("Account scheduled for removal. Undo within 10 seconds.", "success");

    undoTimerRef.current = window.setTimeout(async () => {
      try {
        await deleteManagedUser(account.id);
        setAccounts((prev) => prev.filter((row) => row.id !== account.id));
        showToast("Account removed permanently.", "success");
      } catch (err) {
        showToast(getApiErrorMessage(err), "error");
      } finally {
        setUndoDelete(null);
        setUndoCountdown(0);
        setDeletingId(null);
        undoTimerRef.current = null;
        if (undoIntervalRef.current) {
          window.clearInterval(undoIntervalRef.current);
          undoIntervalRef.current = null;
        }
      }
    }, 10000);
  };

  const undoRemove = () => {
    if (!undoDelete?.account) return;
    if (undoTimerRef.current) {
      window.clearTimeout(undoTimerRef.current);
      undoTimerRef.current = null;
    }
    if (undoIntervalRef.current) {
      window.clearInterval(undoIntervalRef.current);
      undoIntervalRef.current = null;
    }
    setUndoDelete(null);
    setUndoCountdown(0);
    setDeletingId(null);
    showToast("Removal undone.", "success");
  };

  const changeRole = async (account, nextRole) => {
    if (!account?.id || !nextRole || nextRole === account.role) return;
    setUpdatingRoleId(account.id);
    try {
      const { data } = await updateManagedUserRole(account.id, nextRole);
      const updated = data?.account;
      if (updated?.id) {
        setAccounts((prev) =>
          prev.map((row) =>
            row.id === updated.id ? { ...row, role: updated.role } : row,
          ),
        );
      } else {
        await loadAccounts();
      }
      showToast("Role updated.", "success");
    } catch (err) {
      showToast(getApiErrorMessage(err), "error");
    } finally {
      setUpdatingRoleId(null);
    }
  };

  return (
    <div className="dp-page">
      <div className="dp-header">
        <div>
          <h1 className="dp-title">Manage platform accounts</h1>
          <p className="dp-subtitle">
            Create admin, tenant, or customer accounts. Verification code is sent
            by email before first sign-in.
          </p>
        </div>
      </div>

      <form className="ac-form-card" onSubmit={onSubmit} noValidate>
        <div className="ac-form-grid">
          <div className="dp-field">
            <label>Full name</label>
            <input
              type="text"
              value={form.name}
              onChange={(e) => setForm((p) => ({ ...p, name: e.target.value }))}
              placeholder="john doe"
              autoComplete="name"
            />
          </div>
          <div className="dp-field">
            <label>Email</label>
            <input
              type="email"
              value={form.email}
              onChange={(e) =>
                setForm((p) => ({ ...p, email: e.target.value.toLowerCase() }))
              }
              placeholder="admin@example.com"
              autoComplete="email"
            />
          </div>
          <div className="dp-field">
            <label>Role</label>
            <CustomSelect
              options={roleOptions}
              value={form.role}
              onChange={(v) => setForm((p) => ({ ...p, role: v }))}
              placeholder="Select role"
            />
          </div>
          <div className="dp-field">
            <label>Temporary password</label>
            <input
              type="password"
              value={form.password}
              onChange={(e) =>
                setForm((p) => ({ ...p, password: e.target.value }))
              }
              placeholder="At least 6 characters"
              autoComplete="new-password"
            />
            <span className="dp-field-hint">
              User can change password later from profile/reset flow.
            </span>
          </div>
        </div>

        <div className="dt-modal-footer" style={{ padding: 0, borderTop: 0 }}>
          <button type="submit" className="dp-btn-primary" disabled={!canSubmit}>
            <HiOutlineUserAdd size={18} style={{ marginRight: 6 }} />
            {submitting ? "Creating…" : "Create account"}
          </button>
        </div>
      </form>

      <div className="ac-table-wrap" style={{ marginTop: 16 }}>
        <div
          className="dp-header dp-header--row"
          style={{ marginBottom: 12, alignItems: "center" }}
        >
          <h3 className="dp-section-heading" style={{ margin: 0 }}>
            <HiOutlineUserGroup size={18} style={{ marginRight: 6 }} />
            Accounts
          </h3>
          <div className="ac-role-filter-wrap">
            <CustomSelect options={filterOptions} value={roleFilter} onChange={setRoleFilter} />
          </div>
        </div>
        <div className="ac-search-row">
          <div className="dp-bookings-search ac-search-input">
            <HiOutlineSearch size={18} aria-hidden />
            <input
              type="search"
              className="form-control dp-bookings-search-input"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search name or email"
              aria-label="Search accounts by name or email"
              autoComplete="off"
              spellCheck={false}
            />
          </div>
        </div>
        {loadingList ? (
          <p className="ac-muted">Loading accounts…</p>
        ) : accounts.length === 0 ? (
          <p className="ac-muted">No accounts found.</p>
        ) : visibleAccounts.length === 0 ? (
          <p className="ac-muted text-center">No accounts match your search.</p>
        ) : (
          <table className="ac-table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Status</th>
                <th>Created</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {visibleAccounts.map((a) => (
                <tr key={a.id}>
                  <td>{a.name || "—"}</td>
                  <td className="ac-muted">{a.email || "—"}</td>
                  <td>
                    {String(a.id) === String(user?.id) ? (
                      <span className="aba-status aba-status--live">
                        {roleBadgeLabel(a.role)}
                      </span>
                    ) : (
                      <div style={{ minWidth: 140 }}>
                        <CustomSelect
                          options={[
                            { value: "admin", label: "admin" },
                            { value: "tenant", label: "tenant" },
                            { value: "customer", label: "user" },
                          ]}
                          value={a.role}
                          onChange={(v) => changeRole(a, v)}
                          disabled={updatingRoleId === a.id}
                        />
                      </div>
                    )}
                  </td>
                  <td className="ac-muted">
                    {a.isEmailVerified ? "Verified" : "Pending"}
                  </td>
                  <td className="ac-muted">
                    {a.createdAt
                      ? new Date(a.createdAt).toLocaleDateString()
                      : "—"}
                  </td>
                  <td style={{ textAlign: "right" }}>
                    {String(a.id) === String(user?.id) ? (
                      <span className="ac-muted">You</span>
                    ) : (
                      undoDelete?.account?.id === a.id ? (
                        <button
                          type="button"
                          className="dp-btn-primary"
                          onClick={undoRemove}
                          style={{
                            padding: "6px 10px",
                            fontSize: 13,
                            minWidth: 96,
                            fontVariantNumeric: "tabular-nums",
                          }}
                        >
                          Undo ({Math.max(0, undoCountdown)}s)
                        </button>
                      ) : (
                        <button
                          type="button"
                          className="dp-btn-ghost"
                          disabled={deletingId === a.id}
                          onClick={() => confirmRemoveAccount(a)}
                          style={{ padding: "6px 10px", fontSize: 13 }}
                        >
                          <HiOutlineTrash size={15} style={{ marginRight: 6 }} />
                          {deletingId === a.id ? "Removing…" : "Remove"}
                        </button>
                      )
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <VerifyEmailModal
        isOpen={verifyModalOpen}
        onClose={() => setVerifyModalOpen(false)}
        email={pendingEmail}
        onVerify={async (code) => {
          await verifyEmailRequest({ email: pendingEmail, code });
        }}
        onResend={async () => {
          await resendVerificationRequest({ email: pendingEmail });
        }}
        onSuccess={() => {
          setVerifyModalOpen(false);
          showToast("Admin email verified. Account is now active.", "success");
          loadAccounts();
        }}
      />

      {deleteConfirm ? (
        <div className="dt-modal-overlay" role="presentation" onClick={closeDeleteModal}>
          <div
            className="dt-modal mb-delete-modal"
            role="dialog"
            aria-modal="true"
            aria-labelledby="admin-account-delete-title"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="dt-modal-header">
              <h2 id="admin-account-delete-title">Remove account?</h2>
              <button
                type="button"
                className="dt-modal-close"
                onClick={closeDeleteModal}
                aria-label="Close"
                disabled={!!deletingId}
              >
                <HiOutlineX size={20} />
              </button>
            </div>
            <div className="dt-modal-body">
              <p className="mb-delete-modal-text">
                This account will be removed. You can undo this action for 10 seconds
                after confirming.
              </p>
              <p className="dp-closing-delete-preview">
                <span className="dp-closing-kicker">Name</span>{" "}
                {deleteConfirm.name || "—"}
                <br />
                <span className="dp-closing-kicker mt-2">Email</span>{" "}
                {deleteConfirm.email || "—"}
              </p>
            </div>
            <div className="dt-modal-footer">
              <button
                type="button"
                className="dp-action-btn cancel"
                onClick={closeDeleteModal}
                disabled={!!deletingId}
              >
                Cancel
              </button>
              <button
                type="button"
                className="mb-delete-modal-confirm"
                onClick={performDeleteWithUndo}
                disabled={!!deletingId}
              >
                {deletingId ? "Removing…" : "Remove"}
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
}

import { useState, useEffect, useMemo, useCallback } from "react";
import { Link, useOutletContext } from "react-router-dom";
import {
  HiOutlineCalendar,
  HiOutlineCurrencyEuro,
  HiOutlineUsers,
  HiOutlineTrendingUp,
  HiOutlineClock,
  HiOutlineChartBar,
  HiOutlineUserGroup,
  HiOutlineRefresh,
} from "react-icons/hi";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid,
  BarChart,
  Bar,
  Cell,
} from "recharts";
import {
  getRevenueTrend,
  getHeatmap,
  getServicePopularity,
  getStaffUtilization,
  getRetentionCohorts,
} from "../../api/analytics";
import { getApiErrorMessage } from "../../api/auth";
import { formatMoneyCompact, normalizeCurrency } from "../../utils/currency";
import { isAdminRole } from "../../utils/roles";
import DashboardErrorPanel from "../../components/DashboardErrorPanel";
import "./dashboard-pages.css";
import "./analytics-pro.css";

/** Preset ranges — keep them short so the chart stays readable. */
const RANGES = [
  { id: "7d", label: "7 days", days: 7, granularity: "day" },
  { id: "30d", label: "30 days", days: 30, granularity: "day" },
  { id: "90d", label: "90 days", days: 90, granularity: "week" },
  { id: "12m", label: "12 months", days: 365, granularity: "month" },
];

/** Compact weekday labels for the heatmap (Mon-first). */
const SHORT_DAYS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

function rangeParams(rangeId) {
  const r = RANGES.find((x) => x.id === rangeId) || RANGES[1];
  const now = new Date();
  const end = new Date(
    Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1),
  );
  const start = new Date(end);
  start.setUTCDate(start.getUTCDate() - r.days);
  return {
    from: start.toISOString(),
    to: end.toISOString(),
    granularity: r.granularity,
  };
}

function formatPct(n) {
  if (n == null || Number.isNaN(n)) return "—";
  const sign = n > 0 ? "+" : "";
  return `${sign}${n}%`;
}

function formatBucket(iso, granularity) {
  if (!iso) return "";
  const d = new Date(iso);
  if (granularity === "month") {
    return d.toLocaleDateString(undefined, {
      month: "short",
      year: "2-digit",
    });
  }
  if (granularity === "week") {
    return `Wk ${d.toLocaleDateString(undefined, {
      month: "short",
      day: "numeric",
    })}`;
  }
  return d.toLocaleDateString(undefined, { month: "short", day: "numeric" });
}

/** Heatmap cell colour — deeper indigo = busier. Light cells stay readable. */
function heatColor(count, max) {
  if (!max || !count) return "var(--app-surface-3)";
  const ratio = Math.min(1, count / max);
  const alpha = 0.14 + ratio * 0.76;
  return `rgba(99, 102, 241, ${alpha.toFixed(2)})`;
}

function cohortColor(pct) {
  if (pct == null) return "transparent";
  const ratio = Math.min(1, pct / 100);
  const alpha = 0.08 + ratio * 0.82;
  return `rgba(99, 102, 241, ${alpha.toFixed(2)})`;
}

const Analytics = () => {
  const { user, activeWorkspaceId } = useOutletContext();
  const limits = user?.subscription?.limits;
  const subAdmin = Boolean(user?.subscription?.isAdmin);
  const canViewAnalytics =
    subAdmin || isAdminRole(user?.role) || Boolean(limits?.analytics);
  const fetchCohorts =
    subAdmin ||
    isAdminRole(user?.role) ||
    Boolean(limits?.advancedAnalytics);

  const [rangeId, setRangeId] = useState("30d");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [revenue, setRevenue] = useState(null);
  const [heatmap, setHeatmap] = useState(null);
  const [services, setServices] = useState(null);
  const [utilization, setUtilization] = useState(null);
  const [cohorts, setCohorts] = useState(null);

  const load = useCallback(async () => {
    if (!canViewAnalytics) return;
    setLoading(true);
    setError(null);
    const params = rangeParams(rangeId);
    try {
      const cohortReq = fetchCohorts
        ? getRetentionCohorts({ months: 6 })
        : Promise.resolve({ data: null });
      const [r, h, s, u, c] = await Promise.all([
        getRevenueTrend(params),
        getHeatmap(params),
        getServicePopularity({ ...params, limit: 10 }),
        getStaffUtilization(params),
        cohortReq,
      ]);
      setRevenue(r.data);
      setHeatmap(h.data);
      setServices(s.data);
      setUtilization(u.data);
      setCohorts(c.data);
    } catch (err) {
      setError(getApiErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }, [
    rangeId,
    activeWorkspaceId,
    canViewAnalytics,
    fetchCohorts,
    subAdmin,
    user?.role,
  ]);

  useEffect(() => {
    load();
  }, [load]);

  if (!canViewAnalytics) {
    return (
      <div className="dp-page dt-analytics">
        <div className="dp-header">
          <div>
            <h1 className="dp-title">Analytics</h1>
            <p className="dp-subtitle">
              Revenue trends, utilization, and reports are available on
              Professional and Enterprise.
            </p>
          </div>
        </div>
        <div
          className="dt-analytics-card"
          style={{ padding: "24px 28px", maxWidth: 560 }}
        >
          <p style={{ margin: "0 0 16px", color: "var(--app-text-muted)" }}>
            Your current plan does not include analytics. Upgrade to unlock
            dashboards for your workspace.
          </p>
          <Link to="/pricing" className="dp-btn-primary">
            View plans &amp; upgrade
          </Link>
        </div>
      </div>
    );
  }

  const currency = normalizeCurrency(
    revenue?.currency || services?.currency || "EUR",
  );

  const kpis = useMemo(() => {
    if (!revenue) return [];
    return [
      {
        label: "Revenue",
        value: formatMoneyCompact(revenue.totals.revenue, currency),
        change: formatPct(revenue.changePct.revenue),
        up: (revenue.changePct.revenue ?? 0) >= 0,
        icon: <HiOutlineCurrencyEuro size={20} />,
        color: "#10b981",
        bg: "rgba(16, 185, 129, 0.12)",
      },
      {
        label: "Bookings",
        value: String(revenue.totals.bookings),
        change: formatPct(revenue.changePct.bookings),
        up: (revenue.changePct.bookings ?? 0) >= 0,
        icon: <HiOutlineCalendar size={20} />,
        color: "#4f46e5",
        bg: "rgba(79, 70, 229, 0.12)",
      },
      {
        label: "Completed",
        value: String(revenue.totals.completedBookings),
        sub: formatMoneyCompact(revenue.totals.completedRevenue, currency),
        icon: <HiOutlineTrendingUp size={20} />,
        color: "#f59e0b",
        bg: "rgba(245, 158, 11, 0.12)",
      },
      {
        label: "Avg / booking",
        value:
          revenue.totals.bookings > 0
            ? formatMoneyCompact(
                revenue.totals.revenue / revenue.totals.bookings,
                currency,
              )
            : formatMoneyCompact(0, currency),
        icon: <HiOutlineUsers size={20} />,
        color: "#ef4444",
        bg: "rgba(239, 68, 68, 0.12)",
      },
    ];
  }, [revenue, currency]);

  const revenueChartData = useMemo(() => {
    if (!revenue?.series?.length) return [];
    return revenue.series.map((r) => ({
      ...r,
      label: formatBucket(r.bucket, revenue.granularity),
    }));
  }, [revenue]);

  const serviceBarData = useMemo(() => {
    if (!services?.services?.length) return [];
    return services.services.map((s) => ({
      name: s.name,
      bookings: s.bookings,
      revenue: s.revenue,
    }));
  }, [services]);

  return (
    <div className="dp-page dt-analytics">
      <div className="dp-header">
        <div>
          <h1 className="dp-title">Analytics</h1>
          <p className="dp-subtitle">
            Revenue trends, peak hours, service popularity, staff utilization &
            retention.
          </p>
        </div>
        <div className="ana-controls">
          <div className="dt-period-toggle ana-range-toggle">
            {RANGES.map((r) => (
              <button
                key={r.id}
                type="button"
                className={`dt-period-btn ${
                  rangeId === r.id ? "active" : ""
                }`}
                onClick={() => setRangeId(r.id)}
              >
                {r.label}
              </button>
            ))}
          </div>
          <button
            type="button"
            className="ana-refresh-btn"
            onClick={load}
            disabled={loading}
            aria-label="Refresh analytics"
            title="Refresh"
          >
            <HiOutlineRefresh size={16} className={loading ? "spin" : ""} />
          </button>
        </div>
      </div>

      {error ? (
        <DashboardErrorPanel message={error} onRetry={load} />
      ) : (
        <>
          {/* KPI header */}
          <div className="dp-stats-grid">
            {(loading && !revenue ? Array.from({ length: 4 }) : kpis).map(
              (stat, i) => (
                <div key={i} className="dp-overview-stat">
                  {stat ? (
                    <>
                      <div
                        className="dp-overview-icon"
                        style={{ background: stat.bg, color: stat.color }}
                      >
                        {stat.icon}
                      </div>
                      <div className="dp-overview-info">
                        <div className="dt-stat-row">
                          <span
                            className="dp-overview-value"
                            style={{ color: stat.color }}
                          >
                            {stat.value}
                          </span>
                          {stat.change ? (
                            <span
                              className={`dt-change ${stat.up ? "up" : ""}`}
                            >
                              <HiOutlineTrendingUp size={12} /> {stat.change}
                            </span>
                          ) : stat.sub ? (
                            <span className="dt-change">{stat.sub}</span>
                          ) : null}
                        </div>
                        <span className="dp-overview-label">{stat.label}</span>
                      </div>
                    </>
                  ) : (
                    <div className="ana-skeleton ana-skeleton--stat" />
                  )}
                </div>
              ),
            )}
          </div>

          {/* Revenue trend */}
          <div className="dt-analytics-card ana-card-full">
            <div className="ana-card-header">
              <h3>
                <HiOutlineChartBar size={18} /> Revenue trend
              </h3>
              <span className="ana-card-sub">
                {revenue?.granularity === "month"
                  ? "Monthly"
                  : revenue?.granularity === "week"
                    ? "Weekly"
                    : "Daily"}{" "}
                · all non-cancelled bookings
              </span>
            </div>
            <div className="ana-chart-wrap">
              {revenueChartData.length === 0 ? (
                <div className="ana-empty">
                  {loading ? "Loading…" : "No bookings in this range yet."}
                </div>
              ) : (
                <ResponsiveContainer width="100%" height={280}>
                  <AreaChart
                    data={revenueChartData}
                    margin={{ top: 10, right: 18, bottom: 0, left: -8 }}
                  >
                    <defs>
                      <linearGradient id="anaRev" x1="0" y1="0" x2="0" y2="1">
                        <stop
                          offset="5%"
                          stopColor="#6366f1"
                          stopOpacity={0.45}
                        />
                        <stop
                          offset="95%"
                          stopColor="#6366f1"
                          stopOpacity={0}
                        />
                      </linearGradient>
                    </defs>
                    <CartesianGrid
                      stroke="var(--app-border)"
                      strokeDasharray="3 4"
                      vertical={false}
                    />
                    <XAxis
                      dataKey="label"
                      stroke="var(--app-text-muted)"
                      fontSize={11}
                      tickLine={false}
                      axisLine={{ stroke: "var(--app-border)" }}
                    />
                    <YAxis
                      stroke="var(--app-text-muted)"
                      fontSize={11}
                      tickLine={false}
                      axisLine={false}
                      tickFormatter={(v) => formatMoneyCompact(v, currency)}
                      width={72}
                    />
                    <Tooltip
                      contentStyle={{
                        background: "var(--app-surface)",
                        border: "1px solid var(--app-border)",
                        borderRadius: 10,
                        color: "var(--app-text-heading)",
                        boxShadow: "var(--app-shadow-md)",
                      }}
                      labelStyle={{ color: "var(--app-text-heading)" }}
                      formatter={(value, name) => {
                        if (name === "revenue")
                          return [
                            formatMoneyCompact(value, currency),
                            "Revenue",
                          ];
                        return [value, "Bookings"];
                      }}
                    />
                    <Area
                      type="monotone"
                      dataKey="revenue"
                      stroke="#6366f1"
                      fill="url(#anaRev)"
                      strokeWidth={2.2}
                    />
                    <Area
                      type="monotone"
                      dataKey="bookings"
                      stroke="#10b981"
                      fill="transparent"
                      strokeWidth={1.6}
                      strokeDasharray="4 4"
                      hide
                    />
                  </AreaChart>
                </ResponsiveContainer>
              )}
            </div>
          </div>

          <div className="dt-analytics-grid">
            {/* Service popularity */}
            <div className="dt-analytics-card">
              <div className="ana-card-header">
                <h3>
                  <HiOutlineChartBar size={18} /> Service popularity
                </h3>
                <span className="ana-card-sub">By bookings</span>
              </div>
              <div className="ana-chart-wrap ana-chart-wrap--short">
                {serviceBarData.length === 0 ? (
                  <div className="ana-empty">
                    {loading ? "Loading…" : "No services yet."}
                  </div>
                ) : (
                  <ResponsiveContainer
                    width="100%"
                    height={Math.max(240, serviceBarData.length * 36 + 40)}
                  >
                    <BarChart
                      data={serviceBarData}
                      layout="vertical"
                      margin={{ top: 10, right: 28, bottom: 0, left: 10 }}
                    >
                      <CartesianGrid
                        stroke="var(--app-border)"
                        strokeDasharray="3 4"
                        horizontal={false}
                      />
                      <XAxis
                        type="number"
                        stroke="var(--app-text-muted)"
                        fontSize={11}
                        tickLine={false}
                        axisLine={{ stroke: "var(--app-border)" }}
                        allowDecimals={false}
                      />
                      <YAxis
                        dataKey="name"
                        type="category"
                        stroke="var(--app-text-muted)"
                        fontSize={12}
                        tickLine={false}
                        axisLine={false}
                        width={130}
                      />
                      <Tooltip
                        cursor={{ fill: "var(--app-surface-2)" }}
                        contentStyle={{
                          background: "var(--app-surface)",
                          border: "1px solid var(--app-border)",
                          borderRadius: 10,
                          color: "var(--app-text-heading)",
                          boxShadow: "var(--app-shadow-md)",
                        }}
                        formatter={(value, _name, ctx) => {
                          const revenueVal = ctx?.payload?.revenue || 0;
                          return [
                            `${value} · ${formatMoneyCompact(
                              revenueVal,
                              currency,
                            )}`,
                            "Bookings",
                          ];
                        }}
                      />
                      <Bar dataKey="bookings" radius={[0, 6, 6, 0]}>
                        {serviceBarData.map((_e, idx) => (
                          <Cell
                            key={idx}
                            fill={idx === 0 ? "#4f46e5" : "#818cf8"}
                          />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                )}
              </div>
            </div>

            {/* Staff utilization */}
            <div className="dt-analytics-card">
              <div className="ana-card-header">
                <h3>
                  <HiOutlineUserGroup size={18} /> Staff utilization
                </h3>
                <span className="ana-card-sub">Booked / available hours</span>
              </div>
              <div className="ana-util-list">
                {(!utilization?.staff || utilization.staff.length === 0) && (
                  <div className="ana-empty">
                    {loading ? "Loading…" : "No active staff."}
                  </div>
                )}
                {utilization?.staff?.map((s) => {
                  const pct = s.utilization;
                  const pctNum = pct == null ? 0 : Math.min(100, pct);
                  const hoursBooked = Math.round((s.bookedMinutes / 60) * 10) / 10;
                  const hoursAvail =
                    Math.round((s.availableMinutes / 60) * 10) / 10;
                  return (
                    <div key={s.id} className="ana-util-item">
                      <div className="ana-util-head">
                        <div className="ana-util-name-wrap">
                          {s.avatar ? (
                            <img
                              src={s.avatar}
                              alt={s.name}
                              className="ana-util-avatar"
                            />
                          ) : (
                            <div className="ana-util-avatar ana-util-avatar--ph">
                              {s.name?.charAt(0)?.toUpperCase() || "?"}
                            </div>
                          )}
                          <div>
                            <div className="ana-util-name">{s.name}</div>
                            <div className="ana-util-meta">
                              {hoursBooked}h / {hoursAvail}h · {s.bookings}{" "}
                              bookings
                            </div>
                          </div>
                        </div>
                        <div className="ana-util-pct">
                          {pct == null ? "—" : `${pct}%`}
                        </div>
                      </div>
                      <div className="ana-util-bar-bg">
                        <div
                          className="ana-util-bar"
                          style={{ width: `${pctNum}%` }}
                        />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Busiest hours heatmap */}
          <div className="dt-analytics-card ana-card-full">
            <div className="ana-card-header">
              <h3>
                <HiOutlineClock size={18} /> Busiest hours
              </h3>
              <span className="ana-card-sub">
                Bookings by weekday × hour
              </span>
            </div>
            {!heatmap || heatmap.maxCount === 0 ? (
              <div className="ana-empty">
                {loading ? "Loading…" : "No bookings in this range."}
              </div>
            ) : (
              <div className="ana-heatmap-wrap">
                <div className="ana-heatmap-hours" aria-hidden="true">
                  <div className="ana-heatmap-corner" />
                  {Array.from({ length: 24 }).map((_, h) => (
                    <div key={h} className="ana-heatmap-hour-label">
                      {h % 3 === 0 ? `${h.toString().padStart(2, "0")}` : ""}
                    </div>
                  ))}
                </div>
                {heatmap.days.map((row, i) => (
                  <div key={row.dow} className="ana-heatmap-row">
                    <div className="ana-heatmap-day">{SHORT_DAYS[i]}</div>
                    {row.hours.map((cell) => (
                      <div
                        key={cell.hour}
                        className="ana-heatmap-cell"
                        style={{
                          background: heatColor(cell.count, heatmap.maxCount),
                        }}
                        title={`${row.day} ${String(cell.hour).padStart(
                          2,
                          "0",
                        )}:00 — ${cell.count} booking${
                          cell.count === 1 ? "" : "s"
                        }`}
                      />
                    ))}
                  </div>
                ))}
                <div className="ana-heatmap-legend">
                  <span>Fewer</span>
                  {[0.15, 0.3, 0.5, 0.7, 0.9].map((a) => (
                    <span
                      key={a}
                      className="ana-heatmap-legend-cell"
                      style={{ background: `rgba(99, 102, 241, ${a})` }}
                    />
                  ))}
                  <span>Busier</span>
                </div>
              </div>
            )}
          </div>

          {/* Retention cohort */}
          <div className="dt-analytics-card ana-card-full">
            <div className="ana-card-header">
              <h3>
                <HiOutlineUsers size={18} /> Customer retention cohorts
              </h3>
              <span className="ana-card-sub">
                % of customers from their first-booking month who returned
              </span>
            </div>
            {!fetchCohorts ? (
              <div className="ana-empty ana-empty--column">
                <p style={{ margin: 0, maxWidth: 420 }}>
                  Retention cohorts are part of{" "}
                  <strong>Enterprise</strong>. Upgrade to see month-over-month
                  return rates.
                </p>
                <Link
                  to="/pricing"
                  className="dp-btn-primary"
                  style={{ marginTop: 14 }}
                >
                  View Enterprise
                </Link>
              </div>
            ) : !cohorts?.cohorts?.length ||
              cohorts.cohorts.every((c) => c.total === 0) ? (
              <div className="ana-empty">
                {loading ? "Loading…" : "Not enough data yet."}
              </div>
            ) : (
              <div className="ana-cohort-wrap">
                <table className="ana-cohort-table">
                  <thead>
                    <tr>
                      <th className="ana-cohort-th-cohort">Cohort</th>
                      <th className="ana-cohort-th-size">New</th>
                      {cohorts.offsetLabels.map((o) => (
                        <th key={o}>{o}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {cohorts.cohorts.map((c) => (
                      <tr key={c.cohort}>
                        <td className="ana-cohort-label">{c.cohort}</td>
                        <td className="ana-cohort-size">{c.total}</td>
                        {c.cells.map((cell, i) => (
                          <td
                            key={i}
                            className="ana-cohort-cell"
                            style={{
                              background: cohortColor(cell.pct),
                              color:
                                cell.pct != null && cell.pct >= 50
                                  ? "#fff"
                                  : "var(--app-text-heading)",
                            }}
                          >
                            {cell.pct == null ? "—" : `${cell.pct}%`}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default Analytics;

import { useState, useEffect, useMemo, useCallback } from "react";
import { useOutletContext, Navigate, useSearchParams } from "react-router-dom";
import {
  HiOutlineUsers,
  HiOutlineSearch,
  HiOutlineSwitchVertical,
  HiOutlineFilter,
  HiOutlineUserGroup,
  HiOutlineClock,
} from "react-icons/hi";
import "./dashboard-pages.css";
import {
  listBusinesses,
  getBusinessCustomers,
  getBusinessCustomerServiceHistory,
} from "../../api/businesses";
import { getApiErrorMessage } from "../../api/auth";
import { getStoredWorkspaceId } from "../../auth/session";
import {
  DashboardSkeletonStack,
  DashboardSkeletonTable,
} from "../../components/DashboardPageSkeleton";
import DashboardErrorPanel from "../../components/DashboardErrorPanel";
import CustomSelect from "../../utils/CustomSelect";
import { isCustomerRole, isAdminRole } from "../../utils/roles";

/** Completed visits at or above this count count as VIP (highest segment). */
const VIP_COMPLETED_MIN = 6;

function isVipCustomer(row) {
  return (row.completedCount ?? 0) >= VIP_COMPLETED_MIN;
}

const CUSTOMER_SORT_OPTIONS = [
  { value: "name", label: "Name (A–Z)" },
  { value: "reservations", label: "Most reservations" },
  { value: "completed", label: "Most completed visits" },
  { value: "noShows", label: "Most no-shows" },
];

const HISTORY_STATUS_STYLES = {
  completed: { label: "Completed", color: "#4f46e5", bg: "#eef2ff" },
  confirmed: { label: "Confirmed", color: "#10b981", bg: "#ecfdf5" },
  pending: { label: "Pending", color: "#f59e0b", bg: "#fffbeb" },
  pending_confirmation: {
    label: "Confirm time",
    color: "#d97706",
    bg: "#fffbeb",
  },
  cancelled: { label: "Cancelled", color: "#ef4444", bg: "#fef2f2" },
  no_show: { label: "No-show", color: "#64748b", bg: "#f1f5f9" },
};

function formatHistoryDate(d) {
  if (d == null) return "—";
  const dt = d instanceof Date ? d : new Date(d);
  if (Number.isNaN(dt.getTime())) return "—";
  return dt.toLocaleDateString(undefined, {
    weekday: "short",
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

/** Who to include before search — based on completed visit counts only. */
const SEGMENT_OPTIONS = [
  { value: "all", label: "Everyone" },
  { value: "one_plus", label: "Repeat visitors (1+ completed)" },
  { value: "mid", label: "Regulars (2–5 completed)" },
  { value: "loyal", label: "VIP (6+ completed)" },
];

function matchesSegment(row, segment) {
  if (segment === "all") return true;
  const c = row.completedCount ?? 0;
  if (segment === "one_plus") return c >= 1;
  if (segment === "mid") return c >= 2 && c <= 5;
  if (segment === "loyal") return c >= VIP_COMPLETED_MIN;
  return true;
}

const BusinessCustomers = () => {
  const { user, activeWorkspaceId } = useOutletContext();
  const [searchParams, setSearchParams] = useSearchParams();

  const rawSegment = searchParams.get("segment");
  const segment = SEGMENT_OPTIONS.some((o) => o.value === rawSegment)
    ? rawSegment
    : "all";

  const [businesses, setBusinesses] = useState([]);
  const [businessId, setBusinessId] = useState("");
  const [customers, setCustomers] = useState([]);
  const [loadingBusinesses, setLoadingBusinesses] = useState(true);
  const [loadingCustomers, setLoadingCustomers] = useState(false);
  const [error, setError] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [retryNonce, setRetryNonce] = useState(0);
  const [sortBy, setSortBy] = useState("name");
  const [historyTarget, setHistoryTarget] = useState(null);
  const [historyItems, setHistoryItems] = useState([]);
  const [historyLoading, setHistoryLoading] = useState(false);
  const [historyError, setHistoryError] = useState(null);
  const [historyFetchNonce, setHistoryFetchNonce] = useState(0);

  const loadBusinesses = useCallback(async () => {
    if (isCustomerRole(user?.role) || isAdminRole(user?.role)) {
      setLoadingBusinesses(false);
      return;
    }
    setLoadingBusinesses(true);
    setError(null);
    try {
      const { data } = await listBusinesses({ scope: "mine" });
      const list = Array.isArray(data.businesses) ? data.businesses : [];
      setBusinesses(list);
      setBusinessId((prev) => {
        const ws = activeWorkspaceId || getStoredWorkspaceId();
        if (ws && list.some((b) => String(b.id ?? b._id) === ws)) {
          return ws;
        }
        if (prev && list.some((b) => String(b.id ?? b._id) === prev)) {
          return prev;
        }
        if (list.length === 1) {
          return String(list[0].id ?? list[0]._id);
        }
        return "";
      });
    } catch (err) {
      setError(getApiErrorMessage(err));
      setBusinesses([]);
      setBusinessId("");
    } finally {
      setLoadingBusinesses(false);
    }
  }, [user?.role, activeWorkspaceId]);

  useEffect(() => {
    loadBusinesses();
  }, [loadBusinesses]);

  /** Old ?filter=loyal links → ?segment=loyal */
  useEffect(() => {
    if (searchParams.get("filter") !== "loyal") return;
    const p = new URLSearchParams(searchParams);
    p.delete("filter");
    p.set("segment", "loyal");
    setSearchParams(p, { replace: true });
  }, [searchParams, setSearchParams]);

  useEffect(() => {
    const onWs = () => {
      loadBusinesses();
    };
    window.addEventListener("appointly:workspace-changed", onWs);
    return () =>
      window.removeEventListener("appointly:workspace-changed", onWs);
  }, [loadBusinesses]);

  const handleErrorRetry = useCallback(() => {
    setError(null);
    if (!businessId) {
      loadBusinesses();
    } else {
      setRetryNonce((n) => n + 1);
    }
  }, [businessId, loadBusinesses]);

  useEffect(() => {
    if (!businessId) {
      setCustomers([]);
      return;
    }
    let cancelled = false;
    (async () => {
      setLoadingCustomers(true);
      setError(null);
      try {
        const { data } = await getBusinessCustomers(businessId);
        if (!cancelled) {
          setCustomers(Array.isArray(data.customers) ? data.customers : []);
        }
      } catch (err) {
        if (!cancelled) {
          setError(getApiErrorMessage(err));
          setCustomers([]);
        }
      } finally {
        if (!cancelled) setLoadingCustomers(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [businessId, retryNonce]);

  useEffect(() => {
    setSearchQuery("");
  }, [businessId]);

  useEffect(() => {
    setHistoryTarget(null);
    setHistoryItems([]);
    setHistoryError(null);
    setHistoryFetchNonce(0);
  }, [businessId]);

  useEffect(() => {
    if (!historyTarget?.customerId || !businessId) {
      return undefined;
    }
    let cancelled = false;
    (async () => {
      setHistoryLoading(true);
      setHistoryError(null);
      try {
        const { data } = await getBusinessCustomerServiceHistory(
          businessId,
          historyTarget.customerId,
        );
        if (!cancelled) {
          setHistoryItems(Array.isArray(data.items) ? data.items : []);
        }
      } catch (err) {
        if (!cancelled) {
          setHistoryError(getApiErrorMessage(err));
          setHistoryItems([]);
        }
      } finally {
        if (!cancelled) setHistoryLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [historyTarget?.customerId, businessId, historyFetchNonce]);

  useEffect(() => {
    if (segment === "loyal" || segment === "mid") {
      setSortBy("completed");
    }
  }, [segment]);

  const setSegment = useCallback(
    (next) => {
      const p = new URLSearchParams(searchParams);
      if (!next || next === "all") {
        p.delete("segment");
      } else {
        p.set("segment", next);
      }
      setSearchParams(p, { replace: true });
    },
    [searchParams, setSearchParams],
  );

  const displayedCustomers = useMemo(() => {
    let list = customers;
    const q = searchQuery.trim().toLowerCase();
    if (q) {
      list = list.filter((c) => {
        const name = String(c.name ?? "").toLowerCase();
        const email = String(c.email ?? "").toLowerCase();
        return name.includes(q) || email.includes(q);
      });
    }
    if (segment !== "all") {
      list = list.filter((c) => matchesSegment(c, segment));
    }
    const copy = [...list];
    copy.sort((a, b) => {
      switch (sortBy) {
        case "reservations":
          return (
            (b.reservationCount ?? 0) - (a.reservationCount ?? 0)
          );
        case "completed":
          return (b.completedCount ?? 0) - (a.completedCount ?? 0);
        case "noShows":
          return (b.noShowCount ?? 0) - (a.noShowCount ?? 0);
        case "name":
        default:
          return String(a.name ?? "")
            .toLowerCase()
            .localeCompare(String(b.name ?? "").toLowerCase(), undefined, {
              sensitivity: "base",
            });
      }
    });
    return copy;
  }, [customers, searchQuery, segment, sortBy]);

  const segmentCounts = useMemo(() => {
    const base = customers;
    return {
      all: base.length,
      one_plus: base.filter((c) => matchesSegment(c, "one_plus")).length,
      mid: base.filter((c) => matchesSegment(c, "mid")).length,
      loyal: base.filter((c) => matchesSegment(c, "loyal")).length,
    };
  }, [customers]);

  const selectedBusinessName = useMemo(() => {
    const b = businesses.find(
      (x) => String(x.id ?? x._id) === String(businessId),
    );
    return b?.name?.trim() || "";
  }, [businesses, businessId]);

  if (isCustomerRole(user?.role) || isAdminRole(user?.role)) {
    return <Navigate to="/dashboard" replace />;
  }

  const closeHistoryModal = useCallback(() => {
    setHistoryTarget(null);
    setHistoryItems([]);
    setHistoryError(null);
  }, []);

  return (
    <div className="dp-page dp-customers-page">
      {historyTarget ? (
        <div
          className="dt-modal-overlay"
          role="presentation"
          onClick={closeHistoryModal}
        >
          <div
            className="dt-modal dt-modal--scroll dp-customer-history-modal"
            role="dialog"
            aria-modal="true"
            aria-labelledby="dp-customer-history-title"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="dt-modal-header">
              <h2 id="dp-customer-history-title">Service history</h2>
              <button
                type="button"
                className="dt-modal-close"
                onClick={closeHistoryModal}
                aria-label="Close"
              >
                ×
              </button>
            </div>
            <div className="dt-modal-body">
              <p className="dp-customer-history-sub">
                <strong>{historyTarget.name?.trim() || "Customer"}</strong>
                {historyTarget.email?.trim() ? (
                  <>
                    {" "}
                    ·{" "}
                    <a href={`mailto:${historyTarget.email.trim()}`}>
                      {historyTarget.email.trim()}
                    </a>
                  </>
                ) : null}
              </p>
              <p className="dp-customer-history-hint">
                Every visit at this business (expired requests excluded). Newest
                first.
              </p>
              {historyError ? (
                <DashboardErrorPanel
                  message={historyError}
                  onRetry={() => setHistoryFetchNonce((n) => n + 1)}
                />
              ) : null}
              {historyLoading ? (
                <p className="dp-subtitle" role="status">
                  Loading history…
                </p>
              ) : null}
              {!historyLoading && !historyError && historyItems.length === 0 ? (
                <p className="dp-subtitle">No bookings to show.</p>
              ) : null}
              {!historyLoading && historyItems.length > 0 ? (
                <ul className="dp-customer-history-timeline">
                  {historyItems.map((item) => {
                    const st =
                      HISTORY_STATUS_STYLES[item.status] ||
                      HISTORY_STATUS_STYLES.confirmed;
                    const reqT = String(item.requestedStartTime || "").trim();
                    const heldT = String(item.startTime || "").trim();
                    const showReq = Boolean(reqT) && reqT !== heldT;
                    return (
                      <li key={item.id} className="dp-customer-history-item">
                        <div className="dp-customer-history-item-marker" aria-hidden />
                        <div className="dp-customer-history-item-card">
                          <div className="dp-customer-history-item-top">
                            <div className="dp-customer-history-item-when">
                              <HiOutlineClock size={16} aria-hidden />
                              <span>
                                {formatHistoryDate(item.date)} · {heldT}
                                {item.endTime ? `–${item.endTime}` : ""}
                              </span>
                            </div>
                            <span
                              className="dp-customer-history-status"
                              style={{ color: st.color, background: st.bg }}
                            >
                              {st.label}
                            </span>
                          </div>
                          <div className="dp-customer-history-services">
                            {item.servicesLabel}
                          </div>
                          <div className="dp-customer-history-meta">
                            <span>
                              Staff: <strong>{item.staff?.name || "—"}</strong>
                            </span>
                            <span>
                              {item.duration} min · {item.price}{" "}
                              {String(item.currency || "EUR").toUpperCase()}
                            </span>
                          </div>
                          {item.notes ? (
                            <div className="dp-customer-history-notes">
                              <span className="dp-customer-history-notes-label">
                                Notes
                              </span>
                              <p>{item.notes}</p>
                            </div>
                          ) : null}
                          {item.cancellationReason ? (
                            <div className="dp-customer-history-cancel">
                              <span className="dp-customer-history-notes-label">
                                Cancellation
                              </span>
                              <p>{item.cancellationReason}</p>
                            </div>
                          ) : null}
                          {showReq ? (
                            <p className="dp-customer-history-requested">
                              Client requested {reqT} · held {heldT}
                            </p>
                          ) : null}
                        </div>
                      </li>
                    );
                  })}
                </ul>
              ) : null}
            </div>
          </div>
        </div>
      ) : null}

      <div className="dp-header">
        <h1 className="dp-title">Customers</h1>
        <p className="dp-subtitle">
          People who have booked{" "}
          {selectedBusinessName ? (
            <strong>{selectedBusinessName}</strong>
          ) : (
            "your business"
          )}
          . Totals exclude expired bookings. Use <strong>Focus</strong> to slice by
          completed visits (repeat → regulars → VIP); sort independently.
        </p>
      </div>

      {error ? (
        <DashboardErrorPanel message={error} onRetry={handleErrorRetry} />
      ) : (
        <>
      {!loadingBusinesses && businessId ? (
        <div className="dp-customers-toolbar">
          <div className="dp-customers-panel dp-customers-panel--controls">
            <div className="dp-customers-controls-row dp-customers-controls-row--primary">
              <div className="dp-bookings-search dp-customers-search">
                <HiOutlineSearch size={18} aria-hidden />
                <input
                  id="dp-customers-search-input"
                  type="search"
                  className="form-control dp-bookings-search-input"
                  placeholder="Search by name or email…"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoComplete="off"
                  spellCheck={false}
                  aria-label="Search customers by name or email"
                />
              </div>
              <div className="dp-customers-sort-wrap">
                <CustomSelect
                  options={CUSTOMER_SORT_OPTIONS}
                  value={sortBy}
                  onChange={setSortBy}
                  icon={<HiOutlineSwitchVertical size={18} strokeWidth={1.5} />}
                  placeholder="Sort by"
                />
              </div>
            </div>
            <div className="dp-customers-focus-block">
              <div className="dp-customers-focus-label">
                <HiOutlineFilter size={18} aria-hidden />
                <span>Focus (by completed visits)</span>
              </div>
              <div className="dp-customers-focus-row">
                <div className="dp-customers-segment-wrap">
                  <CustomSelect
                    options={SEGMENT_OPTIONS}
                    value={segment}
                    onChange={setSegment}
                    icon={<HiOutlineUserGroup size={18} strokeWidth={1.5} />}
                    placeholder="Who to show"
                  />
                </div>
                <p className="dp-customers-segment-hint" role="status">
                  {segment === "all" ? (
                    <>
                      <strong>{segmentCounts.all}</strong> customers · VIP:{" "}
                      <strong>{segmentCounts.loyal}</strong>
                    </>
                  ) : (
                    <>
                      <strong>{segmentCounts[segment] ?? 0}</strong> in this
                      focus
                      {searchQuery.trim()
                        ? ` · ${displayedCustomers.length} after search`
                        : ""}
                    </>
                  )}
                </p>
              </div>
            </div>
          </div>
        </div>
      ) : null}

      {loadingBusinesses ? <DashboardSkeletonStack rows={2} /> : null}

      {!loadingBusinesses && businesses.length === 0 ? (
        <div className="dp-empty dp-customers-empty">
          <span className="dp-empty-icon" aria-hidden>
            <HiOutlineUsers size={40} />
          </span>
          <h3>No businesses yet</h3>
          <p>Create a business first to see customers who book with you.</p>
        </div>
      ) : null}

      {!loadingBusinesses && businesses.length > 0 && !businessId ? (
        <p className="dp-subtitle">
          Choose a workspace in the sidebar to load customers.
        </p>
      ) : null}

      {businessId && !loadingBusinesses ? (
        <>
          {loadingCustomers ? (
            <DashboardSkeletonTable cols={6} rows={6} />
          ) : null}
          {!loadingCustomers && customers.length === 0 ? (
            <div className="dp-empty dp-customers-empty">
              <span className="dp-empty-icon" aria-hidden>
                <HiOutlineUsers size={40} />
              </span>
              <h3>No customers yet</h3>
              <p>No bookings for this business (excluding expired).</p>
            </div>
          ) : null}
          {!loadingCustomers &&
          customers.length > 0 &&
          displayedCustomers.length === 0 &&
          searchQuery.trim() ? (
            <div className="dp-empty dp-customers-empty dp-customers-search-empty">
              <h3>No matches</h3>
              <p>Try a different name or email.</p>
            </div>
          ) : null}
          {!loadingCustomers &&
          customers.length > 0 &&
          displayedCustomers.length === 0 &&
          !searchQuery.trim() &&
          segment !== "all" ? (
            <div className="dp-empty dp-customers-empty dp-customers-search-empty">
              <h3>Nobody in this focus</h3>
              <p>
                {segment === "loyal"
                  ? `No customers with ${VIP_COMPLETED_MIN}+ completed visits yet. Try “Regulars” or “Everyone”.`
                  : segment === "mid"
                    ? "No customers with 2–5 completed visits. Try another focus."
                    : "No customers with at least one completed visit. Try “Everyone”."}
              </p>
            </div>
          ) : null}
          {!loadingCustomers && displayedCustomers.length > 0 ? (
            <div className="dp-customers-table-wrap">
              <table className="dp-customers-table">
                <thead>
                  <tr>
                    <th scope="col">Name</th>
                    <th scope="col">Email</th>
                    <th scope="col" className="dp-customers-num">
                      Reservations
                    </th>
                    <th scope="col" className="dp-customers-num">
                      Completed
                    </th>
                    <th scope="col" className="dp-customers-num">
                      No-shows
                    </th>
                    <th scope="col" className="dp-customers-history-col">
                      History
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {displayedCustomers.map((row) => (
                    <tr key={row.customerId}>
                      <td>
                        <span className="dp-customers-name-cell">
                          {row.name?.trim() || "—"}
                          {isVipCustomer(row) ? (
                            <span
                              className="dp-customers-vip-badge"
                              title={`${VIP_COMPLETED_MIN}+ completed visits`}
                            >
                              VIP
                            </span>
                          ) : null}
                        </span>
                      </td>
                      <td>
                        {row.email?.trim() ? (
                          <a href={`mailto:${row.email.trim()}`}>
                            {row.email.trim()}
                          </a>
                        ) : (
                          "—"
                        )}
                      </td>
                      <td className="dp-customers-num">
                        {row.reservationCount ?? 0}
                      </td>
                      <td className="dp-customers-num">
                        {row.completedCount ?? 0}
                      </td>
                      <td className="dp-customers-num">
                        {row.noShowCount ?? 0}
                      </td>
                      <td className="dp-customers-history-col">
                        <button
                          type="button"
                          className="dp-customers-history-btn"
                          onClick={() =>
                            setHistoryTarget({
                              customerId: row.customerId,
                              name: row.name,
