                <span className="dt-cal-day-num">{formatNum(day)}</span>
              </div>
              <div className="dt-cal-day-body">
                {hours.map((_, i) => (
                  <div key={i} className="dt-cal-hour-cell" />
                ))}
                {/* Events */}
                {getEventsForDay(dayIdx).map((event) => (
                  <div
