                    <span className="dt-event-service">{event.service}</span>
                    <span className="dt-event-client">
                      {event.client} · {event.staff}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

